const d = $input.first().json;
const esMenor = (d.edad !== undefined) ? d.edad < 18 : false;
const telefonoDestino = esMenor && d.telefonoTutor ? d.telefonoTutor : d.telefono;
const nombreDestino = esMenor && d.nombreTutor ? d.nombreTutor : d.nombre;
let msg;
if (esMenor) {
  msg = `👶 Hola ${nombreDestino}, información sobre la primera cita de *${d.nombre}* en ${$vars.CLINICA_NOMBRE}.\n\n📅 ${d.fechaStr} a las *${d.horaStr}h*\n👨‍⚕️ ${d.doctor || 'nuestro equipo'}\n\nEn breve te enviaremos los documentos para prepararla. 😊`;
} else {
  msg = `🏥 Hola ${d.nombre}, tu *primera visita* ha sido reservada en ${$vars.CLINICA_NOMBRE}.\n\n📅 ${d.fechaStr} a las *${d.horaStr}h*\n👨‍⚕️ ${d.doctor || 'nuestro equipo'}\n\nEn breve te enviamos los formularios. ¿Necesitas cambiarla? 📞 ${$vars.CLINICA_TELEFONO}`;
}
return [{ json: { ...d, esMenor, telefonoDestino, mensaje: msg } }];
